class Solution:
    def circularArrayLoop(self, nums):
        n = len(nums)
        def nxt(i):
            return (i + nums[i]) % n
        for start in range(n):
            forward = nums[start] > 0
            i = start
            path = []
            seen = {}
            ok = True
            while True:
                if (nums[i] > 0) != forward:
                    ok = False
                    break
                if i in seen:
                    cycle_len = len(path) - seen[i]
                    if cycle_len > 1:
                        return True
                    ok = False
                    break
                seen[i] = len(path)
                path.append(i)
                j = nxt(i)
                if j == i:
                    ok = False
                    break
                i = j
            if ok:
                return True
        return False

