class Solution:
    def circularArrayLoop(self, nums):
        n = len(nums)
        def nxt(i):
            return (i + nums[i]) % n
        for start in range(n):
            if nums[start] == 0:
                continue
            slow, fast = start, start
            forward = nums[start] > 0
            def ok(i):
                return (nums[i] > 0) == forward and nxt(i) != i
            while True:
                if not ok(fast):
                    break
                fast2 = nxt(fast)
                if not ok(fast2):
                    break
                fast = nxt(fast2)
                slow = nxt(slow)
                if slow == fast:
                    return True
        return False

