var circularArrayLoop = function(nums) {
    const n = nums.length;
    const nxt = (i) => (((i + nums[i]) % n) + n) % n;
    for (let start = 0; start < n; start++) {
        if (nums[start] === 0) continue;
        let slow = start, fast = start;
        const forward = nums[start] > 0;
        const ok = (i) => (nums[i] > 0) === forward && nxt(i) !== i;
        while (true) {
            if (!ok(fast)) break;
            const fast2 = nxt(fast);
            if (!ok(fast2)) break;
            fast = nxt(fast2);
            slow = nxt(slow);
            if (slow === fast) return true;
        }
    }
    return false;
};
